3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	type Item = { type: string; cursed?: boolean };
17	type Step = { op: string; items: Item[] };
18	type Scenario = { steps: Step[] };
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_SIZE = 3;
22	const BLOCK_BASE_PREMIUM = 60;
23	
24	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
25	
26	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
27	
28	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
29	
30	const countByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const componentGroupPremium = (type: string, count: number): number =>
39	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * basePremiumForType(type);
40	
41	const sumItemBasePremiums = (items: Item[]): number => {
42	  const nonComponents = items.filter((item) => !isComponent(item));
43	  const components = items.filter(isComponent);
44	  const nonComponentsTotal = nonComponents.reduce(
45	    (sum, item) => sum + itemBasePremium(item),
46	    0,
47	  );
48	  const componentsTotal = Array.from(countByType(components)).reduce(
49	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
50	    0,
51	  );
52	  return nonComponentsTotal + componentsTotal;
53	};
54	
55	const itemSurcharge = (item: Item): number =>
56	  item.cursed ? itemBasePremium(item) * CURSED_SURCHARGE_RATE : 0;
57	
58	const sumItemSurcharges = (items: Item[]): number =>
59	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
60	
61	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
62	  const step = (scenario as Scenario).steps[0];
63	  const itemsBase = sumItemBasePremiums(step.items);
64	  const itemSurcharges = sumItemSurcharges(step.items);
65	  const firstInsurance = itemsBase * FIRST_INSURANCE_SURCHARGE;
66	  const premium = Math.ceil(itemsBase + itemSurcharges + firstInsurance + PROCESSING_FEE);
67	  return { results: [{ premium }] };
68	}
